import React, { useState } from "react";
import "./App.css";
import { useSpring, animated } from "react-spring";

// Inline SVG Icons for premium styling
const UserIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
);

const LockIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
);

const MailIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg>
);

const EyeIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>
);

const EyeOffIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>
);

const CheckCircleIcon = () => (
  <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#dc2626" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
);

function App() {
  const [registrationFormStatus, setRegistrationFormStatus] = useState(false);
  const [feedbackMessage, setFeedbackMessage] = useState("");
  const [isSuccess, setIsSuccess] = useState(false);

  // Smooth slide animation using transform translateX
  const formSliderProps = useSpring({
    transform: registrationFormStatus ? "translateX(-50%)" : "translateX(0%)",
  });

  // Nav buttons text color and bottom border animation
  const loginBtnProps = useSpring({
    color: registrationFormStatus ? "rgba(255, 255, 255, 0.4)" : "#fff",
    borderBottom: registrationFormStatus 
      ? "solid 2px transparent"
      : "solid 2px #dc2626", 
  });
  
  const registerBtnProps = useSpring({
    color: registrationFormStatus ? "#fff" : "rgba(255, 255, 255, 0.4)",
    borderBottom: registrationFormStatus
      ? "solid 2px #dc2626"
      : "solid 2px transparent",
  });

  const handleLogin = (username, password) => {
    if (!username || !password) {
      setFeedbackMessage("Please fill in all fields.");
      return;
    }
    setFeedbackMessage("Authenticating...");
    setTimeout(() => {
      setIsSuccess(true);
      setFeedbackMessage(`Welcome back, ${username}!`);
    }, 1200);
  };

  const handleRegister = (name, email, password, confirmPassword) => {
    if (!name || !email || !password || !confirmPassword) {
      setFeedbackMessage("Please fill in all fields.");
      return;
    }
    if (password !== confirmPassword) {
      setFeedbackMessage("Passwords do not match.");
      return;
    }
    setFeedbackMessage("Creating account...");
    setTimeout(() => {
      setIsSuccess(true);
      setFeedbackMessage("Account registered successfully! Welcome aboard.");
    }, 1200);
  };

  const resetPortal = () => {
    setIsSuccess(false);
    setFeedbackMessage("");
  };

  return (
    <div className="login-register-wrapper">
      {isSuccess ? (
        <div className="success-panel">
          <CheckCircleIcon />
          <h3>Authentication Success</h3>
          <p>{feedbackMessage}</p>
          <button className="reset-btn" onClick={resetPortal}>Back to Portal</button>
        </div>
      ) : (
        <>
          <div className="nav-buttons">
            <animated.button
              onClick={() => { setRegistrationFormStatus(false); setFeedbackMessage(""); }}
              id="loginBtn"
              style={loginBtnProps}
            >
              Login
            </animated.button>
            <animated.button
              onClick={() => { setRegistrationFormStatus(true); setFeedbackMessage(""); }}
              id="registerBtn"
              style={registerBtnProps}
            >
              Register
            </animated.button>
          </div>

          {feedbackMessage && (
            <div className={`feedback-alert ${feedbackMessage.includes("fill") || feedbackMessage.includes("match") ? "error" : "info"}`}>
              {feedbackMessage}
            </div>
          )}

          <div className="form-container">
            <animated.div className="form-group" style={formSliderProps}>
              <LoginForm onLogin={handleLogin} />
              <RegisterForm onRegister={handleRegister} />
            </animated.div>
          </div>
        </>
      )}
    </div>
  );
}

function LoginForm({ onLogin }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    onLogin(username, password);
  };

  return (
    <form id="loginform" onSubmit={handleSubmit}>
      <label htmlFor="username">Username</label>
      <div className="input-wrapper">
        <UserIcon />
        <input 
          type="text" 
          id="username" 
          placeholder="Enter username" 
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />
      </div>

      <label htmlFor="password">Password</label>
      <div className="input-wrapper">
        <LockIcon />
        <input 
          type={showPassword ? "text" : "password"} 
          id="password" 
          placeholder="Enter password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <button 
          type="button" 
          className="password-toggle-btn"
          onClick={() => setShowPassword(!showPassword)}
          aria-label={showPassword ? "Hide password" : "Show password"}
        >
          {showPassword ? <EyeOffIcon /> : <EyeIcon />}
        </button>
      </div>

      <div className="forgot-link-container">
        <a href="#forgot" onClick={(e) => e.preventDefault()}>Forgot your password?</a>
      </div>

      <input type="submit" value="Sign In" className="submit" />
    </form>
  );
}

function RegisterForm({ onRegister }) {
  const [fullname, setFullname] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    onRegister(fullname, email, password, confirmPassword);
  };

  return (
    <form id="registerform" onSubmit={handleSubmit}>
      <label htmlFor="fullname">Full Name</label>
      <div className="input-wrapper">
        <UserIcon />
        <input 
          type="text" 
          id="fullname" 
          placeholder="Enter full name"
          value={fullname}
          onChange={(e) => setFullname(e.target.value)}
        />
      </div>

      <label htmlFor="email">Email Address</label>
      <div className="input-wrapper">
        <MailIcon />
        <input 
          type="email" 
          id="email" 
          placeholder="Enter email address"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
      </div>

      <label htmlFor="reg-password">Password</label>
      <div className="input-wrapper">
        <LockIcon />
        <input 
          type={showPassword ? "text" : "password"} 
          id="reg-password" 
          placeholder="Create password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <button 
          type="button" 
          className="password-toggle-btn"
          onClick={() => setShowPassword(!showPassword)}
          aria-label={showPassword ? "Hide password" : "Show password"}
        >
          {showPassword ? <EyeOffIcon /> : <EyeIcon />}
        </button>
      </div>

      <label htmlFor="confirmpassword">Confirm Password</label>
      <div className="input-wrapper">
        <LockIcon />
        <input 
          type={showPassword ? "text" : "password"} 
          id="confirmpassword" 
          placeholder="Confirm password"
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
        />
      </div>

      <input type="submit" value="Register Now" className="submit" />
    </form>
  );
}

export default App;
